#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0; char ch=getchar(); bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=2e5+10;
int Q[1001][1001];
struct Gragh
{
	int head[N],des[M],cst[M],cap[M],nxt[M],cnt;
	inline void ins(int x,int y,int z,int c){des[++cnt]=y;nxt[cnt]=head[x];cap[cnt]=z;cst[cnt]=c;head[x]=cnt;}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;
int s,t,que[N],H,T,dis[N],mnf[N],pre[N],edg[N],tot,Cap[N];bool inq[N],vis[N];
inline bool spfa()
{
	memset(dis,-0x7f,sizeof(dis));dis[s]=0;
	mnf[s]=-dis[0];inq[que[H=T=1]=s]=1;while(H<=T)
	{
		int u;inq[u=que[H++]]=0;grep(a,u,i)if(!vis[i])
		{
			int v=a.des[i];if(a.cap[i]&&dis[u]+a.cst[i]>dis[v])
			{
				dis[v]=dis[u]+a.cst[i];mnf[v]=min(mnf[u],a.cap[i]);
				pre[v]=i;if(!inq[v])inq[que[++T]=v]=1;
			}
		}
	}return dis[t]!=dis[0];
}
void update(int &mxf,int &mnc)
{
	int v=t;while(v^s){int i=pre[v];a.cap[i]-=mnf[t];a.cap[i^1]+=mnf[t];v=a.des[i^1];}
	mxf+=mnf[t];mnc+=dis[t]*mnf[t];
}
inline void EK(int u,int v,int &mxf,int &mnc){s=u,t=v;while(spfa())update(mxf,mnc);return;}
int main()
{
	int n=read();a.Init();rep(1,n,i)rep(1,n,j)Q[i][j]=read();
	rep(1,n,i)
	{
		a.ins(2*n+1,i,1,0);a.ins(i,2*n+1,0,0);
		a.ins(i+n,2*n+2,1,0);a.ins(2*n+2,i+n,0,0);
		rep(1,n,j){a.ins(i,j+n,1,Q[i][j]);a.ins(j+n,i,0,-Q[i][j]);}
	}
	rep(1,a.cnt,i)Cap[i]=a.cap[i];
	int mnc=0,mxf=0;EK(2*n+1,2*n+2,mxf,mnc);printf("%d\n",mnc);
	for(int i=2;i<=a.cnt;i+=2)if(a.des[i^1]^(2*n+1)&&a.des[i]^(2*n+2)&&!a.cap[i])edg[++tot]=i;
	rep(1,tot,i)
	{
		int p=edg[i];vis[p]=vis[p^1]=1;
		memcpy(a.cap,Cap,sizeof(Cap));
		int tmp=0;EK(2*n+1,2*n+2,mxf,tmp);
		if(tmp^mnc){printf("%d %d\n",a.des[p^1],a.des[p]-n);}
//		printf("%d->%d: %d\n",a.des[p^1],a.des[p]-n,tmp);
		vis[p]=vis[p^1]=0;
	}
}
